module hazard_detection_counter (
    input wire clk,
    input wire reset,
    output reg [1:0] count
);
    reg [1:0] next_counter_value;

    always @(*) begin
        if (reset) begin
            next_counter_value = 2'b00;
        end else begin
            case (count)
                2'b00: next_counter_value = 2'b01;
                2'b01: next_counter_value = 2'b10;
                2'b10: next_counter_value = 2'b11;
                2'b11: next_counter_value = 2'b00;
                default: next_counter_value = 2'b00;
            endcase
        end
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= next_counter_value;
        end
    end
endmodule
